#include <stdio.h>
#include <stdlib.h>
int compare(const void *a, const void *b) {
    return (*(int*)a - *(int*)b);
}
int main() {
    int T;
    scanf("%d", &T);
    while (T--) {
        int N, Z;
        scanf("%d %d", &N, &Z);
        int *A = (int*)malloc(N * sizeof(int));
        for (int i = 0; i < N; i++) {
            scanf("%d", &A[i]);
        }
        qsort(A, N, sizeof(int), compare);
        int *dp = (int*)malloc((Z + 1) * sizeof(int));
        dp[0] = 0;
        for (int i = 1; i <= Z; i++) {
            dp[i] = dp[i - 1] + A[i - 1];
        }
        printf("%d\n", dp[Z]);
        free(A);
        free(dp);
    }
    return 0;
}

