import java.util.Arrays;
import java.util.Scanner;
public class Main {
    public static void main(String[] args) {
        Scanner sc = new Scanner(System.in);
        int T = sc.nextInt();
        while (T-- > 0) {
            int N = sc.nextInt();
            int Z = sc.nextInt();
            int[] A = new int[N];
            for (int i = 0; i < N; i++) {
                A[i] = sc.nextInt();
            }
            Arrays.sort(A);
            int[] dp = new int[Z + 1];
            dp[0] = 0;
            for (int i = 1; i <= Z; i++) {
                dp[i] = dp[i - 1] + A[i - 1];
            }
            System.out.println(dp[Z]);
        }
    }
}

